def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        score = 0.0
        ratio = item / capacity
        decay = 1.0
        steps = 10
        penalty_applied = False
        for step in range(steps):
            exp_part = np.exp(-ratio * (step + 1))
            tanh_part = np.tanh(ratio * 12 * (step + 1))
            log_part = np.log1p(ratio * 120) / (step + 1.5)
            sin_part = (np.sin(ratio * np.pi * (step + 0.7))) ** 3
            complex_term = (exp_part * tanh_part + log_part * sin_part) * decay
            score += complex_term
            if ratio < 0.25:
                score += ((7 - step) * 0.25 * decay)
            elif 0.4 < ratio < 0.8:
                score -= (step ** 1.2) * 0.4 * decay
            elif ratio > 1.05:
                score += 40 * decay
                penalty_applied = True
                break
            else:
                score += (0.15 * step * decay)
            decay *= 0.7
            if score > 20:
                break
        if not penalty_applied:
            if 0.3 <= ratio <= 0.6:
                for k in range(4):
                    adjust = (((0.6 - ratio) * (k + 1)) ** 2) * 0.5
                    score += adjust
                    if adjust > 2:
                        break
            elif ratio > 0.9:
                for k in range(3):
                    if capacity < item * (1 + 0.15 * k):
                        score += 4 * (k + 1)
            if capacity < item * 0.9:
                score += 30
            if capacity > item * 2.5:
                score /= 1.8
            if score < 0:
                score = abs(score) * 0.6
        if np.isnan(score) or np.isinf(score):
            priorities[i] = float('inf')
        else:
            priorities[i] = score
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return np.full_like(priorities, float('inf'))
    p_min = np.min(finite)
    p_max = np.max(finite)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = p_min * 250
        else:
            if priorities[i] == p_min:
                priorities[i] = 0
            elif priorities[i] == p_max:
                priorities[i] *= 2.0
            else:
                val = (priorities[i] - p_min) / (p_max - p_min)
                if val < 0.1:
                    priorities[i] = val * 15
                elif val > 0.9:
                    priorities[i] = val * 30
                else:
                    priorities[i] = val * 20 + (np.sin(val * np.pi) * 5)
    return priorities
